  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      component: { 
        type: Type.STRING, 
        description: "Standard component name (e.g., 'Main Shaft', 'Mechanical Seal')." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          location: { type: Type.STRING },
          visualCues: { type: Type.STRING }
        },
        required: ["description", "location", "visualCues"]
      },
      function: { type: Type.STRING },
      functionalFailure: { type: Type.STRING },
      failureMode: { type: Type.STRING },
      failureEffect: { type: Type.STRING },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ]
      },
      iso14224Code: { type: Type.STRING },
      criticality: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
      severity: { type: Type.INTEGER },
      occurrence: { type: Type.INTEGER },
      detection: { type: Type.INTEGER },
      maintenanceTask: { type: Type.STRING },
      interval: { type: Type.STRING },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement'
        ]
      }
    },
    required: ["component", "componentIntel", "function", "functionalFailure", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

const auditReportSchema = {
  type: Type.OBJECT,
  properties: {
    overallScore: { type: Type.INTEGER },
    coveragePercentage: { type: Type.INTEGER },
    summary: { type: Type.STRING },
    insights: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          category: { 
            type: Type.STRING, 
            enum: ['Missing Failure Mode', 'Strategy Optimization', 'Granularity Difference', 'Risk Variance'] 
          },
          aiObservation: { type: Type.STRING },
          humanVersion: { type: Type.STRING },
          recommendation: { type: Type.STRING },
          severity: { type: Type.STRING, enum: ['Critical', 'Moderate', 'Low'] }
        },
        required: ["category", "aiObservation", "humanVersion", "recommendation", "severity"]
      }
    }
  },
  required: ["overallScore", "coveragePercentage", "summary", "insights"]
