const inspectionSchema = {
  type: Type.OBJECT,
  properties: {
    responsibility: { type: Type.STRING },
    estimatedTime: { type: Type.STRING },
    safetyPrecautions: { type: Type.STRING },
    toolsRequired: { type: Type.STRING },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          step: { type: Type.INTEGER },
          description: { type: Type.STRING },
          criteria: { type: Type.STRING },
          technique: { type: Type.STRING }
        },
        required: ["step", "description", "criteria", "technique"]
      }
    }
  },
  required: ["responsibility", "estimatedTime", "safetyPrecautions", "toolsRequired", "steps"]
};

export const extractOperationalContext = async (fileData: FileData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { inlineData: { mimeType: fileData.mimeType, data: fileData.data } },
        { text: "Extract and summarize the operational context, asset configuration, and environmental conditions from this document for an RCM study. Use technical, professional language." }
      ]
    }
  });
  return response.text || "";
};

export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const parts: any[] = [];
  if (fileData) parts.push({ inlineData: { mimeType: fileData.mimeType, data: fileData.data } });
  parts.push({ text: `Operational Context: ${contextText}` });

  const avoidance = existingItems.length > 0 
    ? `Avoid duplicating: ${existingItems.map(i => i.failureMode).join(", ")}.` 
    : "";

  parts.push({ text: `Generate a detailed RCM analysis. ${avoidance} Ensure Level 4 technical granularity.` });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      systemInstruction: "You are a Senior Reliability Engineer. Provide professional RCM/FMECA analysis."
    }
  });

  const raw = JSON.parse(response.text || "[]");
  return raw.map((item: any) => ({
    ...item,
    id: `rcm-${Math.random().toString(36).substr(2, 9)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1)
  }));
};

export const performRCMGapAnalysis = async (
  aiItems: RCMItem[],
  humanFileData: FileData
): Promise<AuditReport> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const aiDataSummary = aiItems.map(i => ({
    component: i.component,
    mode: i.failureMode,
    task: i.maintenanceTask,
    risk: i.rpn
  }));

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: {
      parts: [
        { inlineData: { mimeType: humanFileData.mimeType, data: humanFileData.data } },
        { text: `Compare this human-made RCM sheet against the AI-generated baseline: ${JSON.stringify(aiDataSummary)}. Identify missing failure modes, strategy optimizations, and risk variances.` }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: auditReportSchema
    }
  });

  return JSON.parse(response.text || "{}") as AuditReport;
};

export const generateInspectionSheet = async (item: RCMItem): Promise<InspectionSheet> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a detailed maintenance inspection sheet for this failure mode: ${item.component} - ${item.failureMode}. Task: ${item.maintenanceTask}.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: inspectionSchema
    }
  });
  return JSON.parse(response.text || "{}") as InspectionSheet;
};

export const generateComponentIntel = async (componentName: string): Promise<ComponentIntel> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Provide technical metadata for the component: ${componentName}. Description, location, and visual identifiers.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          location: { type: Type.STRING },
          visualCues: { type: Type.STRING }
        },
        required: ["description", "location", "visualCues"]
      }
    }
  });
  return JSON.parse(response.text || "{}") as ComponentIntel;
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext, performRCMGapAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder, AuditReport } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { AuditDashboard } from './components/AuditDashboard';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch,
  CheckCircle2,
  ShieldCheck,
  FileWarning
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload' | 'audit'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [auditFileData, setAuditFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsLoadingExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [auditReport, setAuditReport] = useState<AuditReport | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  const [history, setHistory] = useState<RCMItem[][]>([]);
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) setShowWelcome(true);
      try {
        const [studies, fetchedFolders] = await Promise.all([getAllStudies(), getAllFolders()]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        setError("Could not load saved data.");
      }
    };
    initData();
  }, []);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, type: 'context' | 'audit') => {
    const file = event.target.files?.[0];
    if (!file) return;
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        const data = {
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        };
        if (type === 'context') setFileData(data);
        else setAuditFileData(data);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleAudit = async () => {
    if (!auditFileData || !results) {
      setError("Please generate AI results and upload a human sheet for comparison.");
      return;
    }
    setIsLoading(true);
    try {
      const report = await performRCMGapAnalysis(results, auditFileData);
      setAuditReport(report);
    } catch (e) {
      setError("Audit failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsLoadingExtracting(true);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
    } catch (err) {
      setError("Extraction failed.");
    } finally {
      setIsLoadingExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Context required.");
      return;
    }
    setIsLoading(true);
    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);
      setResults(isMerging && results ? [...results, ...data] : data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSaveStudy = async () => {
    if (!results) return;
    const study: SavedStudy = {
      id: currentStudyId || `study-${Date.now()}`,
      name: studyName,
      timestamp: Date.now(),
      items: results,
      contextText,
      fileName: fileData?.name,
      isFinished
    };
    await saveStudyToDB(study);
    setJustSaved(true);
    setTimeout(() => setJustSaved(false), 2000);
    const studies = await getAllStudies();
    setSavedStudies(studies);
    if (!currentStudyId) setCurrentStudyId(study.id);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={() => setShowWelcome(false)} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={() => {}} canUndo={false} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={() => {}} canUndo={false} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={setContextText} onUndo={() => {}} canUndo={false} />
      <AICopilot data={results} onUpdate={setResults} />

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} folders={folders} currentStudyId={currentStudyId} 
          onSelect={(s) => { setResults(s.items); setContextText(s.contextText); setStudyName(s.name); setCurrentStudyId(s.id); }} 
          onDelete={deleteStudyFromDB} onNew={() => { setResults(null); setStudyName("New Analysis"); setCurrentStudyId(null); }}
          onNewFolder={saveFolderToDB} onDeleteFolder={deleteFolderFromDB} onMoveStudy={() => {}} 
          onExport={() => {}} onExportFolder={() => {}} onImport={() => {}} onToggleFinished={() => {}}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <header className="bg-white border-b border-slate-200 h-20 px-6 flex items-center justify-between shadow-sm shrink-0">
          <div className="flex items-center gap-4">
            <button className="md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu /></button>
            <input value={studyName} onChange={e => setStudyName(e.target.value)} className="text-xl font-black bg-transparent outline-none border-b-2 border-transparent focus:border-indigo-500" />
          </div>
          <button onClick={handleSaveStudy} className={`flex items-center gap-2 px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${justSaved ? 'bg-emerald-600 text-white' : 'bg-indigo-600 text-white'}`}>
            <Save size={16} /> {justSaved ? "Saved" : "Save Study"}
          </button>
        </header>

        <main className="flex-1 overflow-y-auto p-6 bg-slate-50/50">
          <div className="max-w-7xl mx-auto space-y-10">
            <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
              <div className="flex border-b border-slate-100 bg-slate-50/50">
                {['manual', 'upload', 'audit'].map((t) => (
                  <button key={t} onClick={() => setActiveTab(t as any)} className={`px-8 py-5 text-[11px] font-black uppercase tracking-widest border-b-2 ${activeTab === t ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400'}`}>
                    {t}
                  </button>
                ))}
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-4">
                    <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Context</span><button onClick={() => setShowContextBuilder(true)} className="text-indigo-600 font-black text-[10px] uppercase">Open Wizard</button></div>
                    <textarea value={contextText} onChange={e => setContextText(e.target.value)} className="w-full h-48 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] outline-none" placeholder="Enter asset details..." />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="border-2 border-dashed border-slate-200 rounded-[2rem] p-12 text-center relative">
                    <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => handleFileUpload(e, 'context')} />
                    <Upload className="mx-auto mb-4 text-slate-300" size={48} />
                    <p className="text-sm font-black text-slate-400 uppercase tracking-widest">{fileData ? fileData.name : "Upload Documentation"}</p>
                    {fileData && <button onClick={handleExtractContext} className="mt-4 bg-indigo-600 text-white px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest">Process</button>}
                  </div>
                )}
                {activeTab === 'audit' && (
                  <div className="space-y-6">
                    <div className="p-8 bg-indigo-50 rounded-[2rem] border border-indigo-100 flex items-center gap-6">
                      <div className="p-4 bg-white rounded-2xl shadow-sm"><ShieldCheck className="text-indigo-600" size={32} /></div>
                      <div>
                        <h4 className="text-lg font-black text-indigo-900 uppercase">RCM Auditor</h4>
                        <p className="text-sm text-indigo-600/70 font-medium italic">Upload your existing manual RCM sheet to find gaps and optimizations against the AI baseline.</p>
                      </div>
                    </div>
                    <div className="border-2 border-dashed border-indigo-200 rounded-[2rem] p-12 text-center relative bg-white">
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => handleFileUpload(e, 'audit')} />
                      <FileWarning className="mx-auto mb-4 text-indigo-300" size={48} />
                      <p className="text-sm font-black text-indigo-400 uppercase tracking-widest">{auditFileData ? auditFileData.name : "Select Human-Made RCM Sheet"}</p>
                    </div>
                    <button onClick={handleAudit} disabled={!auditFileData || !results} className="w-full py-4 bg-slate-900 text-white rounded-[1.5rem] font-black uppercase tracking-widest disabled:opacity-30">Run Audit Analysis</button>
                  </div>
                )}
                <div className="mt-8 flex justify-end">
                   <button onClick={handleGenerate} className="px-10 py-4 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase tracking-widest shadow-xl shadow-indigo-100">{isLoading ? "Processing..." : "Generate RCM Analysis"}</button>
                </div>
              </div>
            </div>

            {auditReport && <AuditDashboard report={auditReport} onClose={() => setAuditReport(null)} />}
            {results && <AnalysisResult data={results} onUpdate={setResults} onUndo={() => {}} canUndo={false} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  MessageSquare, X, Send, Bot, Sparkles, ChevronDown, 
  Plus, Check, ListChecks, CheckCircle2,
  AlertTriangle, Wrench, Layers, Info, Tag, RotateCcw, Cpu, ChevronRight,
  Clock, Search, UserCheck, ShieldAlert, Zap
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
  isFacilitatorInsight?: boolean;
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model'; isFacilitator?: boolean }> = ({ text, role, isFacilitator }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        // Detect if line is a question - make it stand out for the Facilitator persona
        const isQuestion = cleanLine.endsWith('?');

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className={`flex-1 text-[13px] font-medium leading-relaxed ${isQuestion ? 'text-indigo-700 font-bold italic' : ''}`}>
                {cleanLine.replace(/^[*|-]\s*/, '')}
              </span>
            </div>
          );
        }

        if (idx === 0 && role === 'model' && cleanLine.length < 50 && !cleanLine.endsWith('.')) {
          return (
            <h4 key={idx} className="font-black text-[11px] uppercase tracking-widest text-indigo-600 mb-2 border-b border-slate-100 pb-1">
              {cleanLine}
            </h4>
          );
        }

        return (
          <p key={idx} className={`leading-relaxed text-[13px] font-medium ${isQuestion && role === 'model' ? 'bg-indigo-50 p-2 rounded-lg border-l-4 border-indigo-600 text-indigo-900 shadow-sm' : ''}`}>
            {cleanLine}
          </p>
        );
      })}
    </div>
  );
};

