    if (proposal.type === 'ADD') {
      const s = Number(proposal.item.severity) || 5;
      const o = Number(proposal.item.occurrence) || 3;
      const d = Number(proposal.item.detection) || 4;

      const newItem: RCMItem = {
        id: `rcm-mir-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'New Component',
        function: proposal.item.function || 'General Function',
        functionalFailure: proposal.item.functionalFailure || 'Operational Loss',
        failureMode: proposal.item.failureMode || 'General Mechanism',
        failureEffect: proposal.item.failureEffect || 'System Impact',
        consequenceCategory: (proposal.item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'UNC',
        criticality: proposal.item.criticality as any || (s >= 8 ? 'High' : s >= 5 ? 'Medium' : 'Low'),
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        maintenanceTask: proposal.item.maintenanceTask || 'Inspection',
        interval: proposal.item.interval || 'Monthly',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        componentIntel: {
          description: proposal.item.componentIntel?.description || 'Facilitator-generated technical metadata.',
          location: proposal.item.componentIntel?.location || 'Asset primary assembly.',
          visualCues: proposal.item.componentIntel?.visualCues || 'Industrial identifiers.'
        },
        isNew: true
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && proposal.item.id) {
      newData = newData.map(item => {
        if (item.id === proposal.item.id) {
          const updated = { ...item, ...proposal.item, isNew: false };
          updated.severity = Number(updated.severity) || item.severity;
          updated.occurrence = Number(updated.occurrence) || item.occurrence;
          updated.detection = Number(updated.detection) || item.detection;
          updated.rpn = updated.severity * updated.occurrence * updated.detection;
          return updated;
        }
        return item;
      });
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[700px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-slate-900 p-6 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-2 bg-indigo-500/20 rounded-xl border border-indigo-400/30">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-xl tracking-tighter uppercase leading-none">MIRA <span className="text-[10px] text-indigo-400 tracking-widest ml-1">Facilitator</span></h3>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] mt-1">Socratic Reliability Workshop</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-all"><ChevronDown size={28} /></button>
          </div>

          <div className="bg-indigo-50/50 px-6 py-3 border-b border-indigo-100 flex items-center justify-between gap-3 shrink-0">
             <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-widest">
               <ShieldAlert size={14} /> Workshop Audit
             </div>
             <button 
               onClick={handleFacilitatorAudit} 
               disabled={!data || data.length === 0 || isLoading}
               className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all disabled:opacity-30"
             >
               <Search size={12} /> Facilitate Audit
             </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-8">
                <div className="w-20 h-20 bg-white text-indigo-600 rounded-[2.2rem] flex items-center justify-center shadow-2xl border border-indigo-50"><UserCheck size={36} /></div>
                <div className="space-y-4">
                  <p className="text-xl font-black text-slate-900 tracking-tighter uppercase leading-tight">Ready to facilitate</p>
                  <p className="text-[13px] text-slate-500 font-medium italic">I guide your study towards human RCM excellence. Ask me to audit your analysis or suggest missing modes.</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-5 rounded-[2rem] shadow-lg relative ${
                  m.role === 'user' 
                    ? 'bg-slate-900 text-white rounded-br-none font-bold text-[14px]' 
                    : m.isFacilitatorInsight 
                      ? 'bg-white border-2 border-indigo-500 rounded-bl-none shadow-indigo-100'
                      : 'bg-white text-slate-800 border-2 border-slate-100 rounded-bl-none shadow-slate-100/10'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} isFacilitator={m.isFacilitatorInsight} />
                </div>

                {m.proposals && (
                  <div className="mt-6 w-full space-y-4 animate-in slide-in-from-top-4 duration-700">
                    <div className="flex items-center gap-2 px-2">
                       <LayoutGrid size={14} className="text-indigo-400" />
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Facilitator Suggestions</span>
                    </div>
                    {m.proposals.map((p) => (
                      <div key={p.id} className={`bg-white border-2 rounded-[2rem] p-6 shadow-xl relative overflow-hidden transition-all ${p.applied ? 'border-emerald-500 bg-emerald-50/30' : 'border-indigo-100 ring-4 ring-indigo-50/50'}`}>
                        <div className="flex justify-between items-start gap-4">
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-3">
                              <span className={`text-[9px] font-black uppercase tracking-[0.2em] px-2 py-0.5 rounded-full ${p.applied ? 'bg-emerald-500 text-white' : 'bg-indigo-600 text-white'}`}>
                                {p.applied ? 'Study Synced' : `${p.type} Request`}
                              </span>
                              <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{p.item?.taskType || 'RCM Logic'}</span>
                            </div>

                            <h5 className="text-sm font-black text-slate-900 uppercase truncate leading-none mb-2">{p.item?.component}</h5>
                            <div className="space-y-3">
                               <p className="text-[11px] font-bold text-slate-600 leading-tight border-l-2 border-indigo-200 pl-3 italic">{p.reason}</p>
                               <div className="grid grid-cols-2 gap-2 mt-3">
                                  <div className="bg-slate-50 p-2.5 rounded-xl border border-slate-100">
                                     <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Proposed Mode</span>
                                     <span className="text-[10px] font-bold text-slate-700 truncate block leading-none">{p.item?.failureMode || 'Drafting...'}</span>
                                  </div>
                                  <div className="bg-slate-50 p-2.5 rounded-xl border border-slate-100">
                                     <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Strategic Task</span>
                                     <span className="text-[10px] font-bold text-indigo-600 truncate block leading-none">{p.item?.maintenanceTask || 'Analysis...'}</span>
                                  </div>
                               </div>
                               <div className="flex items-center gap-4 mt-2 px-1">
                                  <div className="flex items-center gap-1.5">
                                     <Zap size={10} className="text-amber-500" />
                                     <span className="text-[9px] font-black text-slate-500 uppercase">RPN: {((p.item?.severity || 0) * (p.item?.occurrence || 0) * (p.item?.detection || 0)) || 'TBD'}</span>
                                  </div>
                                  <div className="flex items-center gap-1.5">
                                     <Target size={10} className="text-indigo-500" />
                                     <span className="text-[9px] font-black text-slate-500 uppercase">{p.item?.interval || 'TBD'}</span>
                                  </div>
                               </div>
                            </div>
                          </div>

                          {!p.applied ? (
                             <button 
                               onClick={() => applySingleAction(p.id, i)} 
                               className="shrink-0 w-16 h-16 bg-indigo-600 text-white rounded-[1.5rem] shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-90 transition-all flex items-center justify-center group"
                               title="Import to RCM Table"
                             >
                               <Plus size={32} className="group-hover:rotate-90 transition-transform" />
                             </button>
                          ) : (
                             <div className="shrink-0 w-16 h-16 bg-emerald-500 text-white rounded-[1.5rem] shadow-lg flex items-center justify-center animate-in zoom-in">
                               <CheckCircle2 size={32} />
                             </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-100 p-4 rounded-full flex items-center gap-3 shadow-sm">
                  <Loader2 size={16} className="animate-spin text-indigo-600" />
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">MIRA facilitating...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-4">
              <button onClick={() => setMessages([])} className="p-4 bg-slate-50 text-slate-400 hover:text-indigo-600 rounded-[1.5rem] border border-slate-100 transition-all"><RotateCcw size={20} /></button>
              <div className="flex-1 relative">
                <input type="text" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} placeholder="Ask MIRA for workshop guidance..." className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] px-6 py-4 text-[14px] font-bold focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 shadow-inner" />
              </div>
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="p-4 bg-indigo-600 text-white rounded-[1.5rem] hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"><Send size={20} /></button>
            </div>
          </div>
        </div>
      )}

      <button onClick={() => setIsOpen(!isOpen)} className={`relative w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 z-[60] border-2 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}>
        {isOpen ? <X size={28} /> : <UserCheck size={28} />}
        {!isOpen && messages.length > 0 && <div className="absolute -top-1 -right-1 w-5 h-5 bg-emerald-500 border-2 border-white rounded-full animate-pulse" />}
      </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  X, Send, Sparkles, ChevronDown, 
  Plus, CheckCircle2, Search, 
  UserCheck, ShieldAlert, Zap, Loader2, LayoutGrid, 
  ChevronRight, RotateCcw, Target, Info
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
  isFacilitatorInsight?: boolean;
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model'; isFacilitator?: boolean }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        const isQuestion = cleanLine.endsWith('?');

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className={`flex-1 text-[13px] font-medium leading-relaxed ${isQuestion ? 'text-indigo-700 font-bold italic' : ''}`}>
                {cleanLine.replace(/^[*|-]\s*/, '')}
              </span>
            </div>
          );
        }

        return (
          <p key={idx} className={`leading-relaxed text-[13px] font-medium ${isQuestion && role === 'model' ? 'bg-indigo-50 p-2 rounded-lg border-l-4 border-indigo-600 text-indigo-900 shadow-sm' : ''}`}>
            {cleanLine}
          </p>
        );
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [isOpen, messages]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object') {
            proposals.push({
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              type: a.type || 'ADD',
              reason: a.reason || 'Facilitator recommendation based on operational logic.',
              item: a.item || {},
              applied: false
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse MIRA action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleFacilitatorAudit = async () => {
    if (!data || data.length === 0) return;
    setIsLoading(true);
    setIsOpen(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const studySummary = data.map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        CURRENT STUDY: ${JSON.stringify(studySummary)}

        TASK:
        Perform a technical Facilitator Audit. You are MIRA. 
        Focus on:
        1. Human-Factor risks (Installation/Maintenance errors).
        2. Strategic gaps in hidden failure detection.
        3. Reliability improvements for high-RPN items.

        MANDATORY RESPONSE FORMAT:
        - Conversational text (probing questions/insight).
        - If suggesting a new failure mode or task, include:
        <ACTION>
        {
          "type": "ADD",
          "reason": "Engineering justification",
          "item": {
            "component": "Component name",
            "function": "Primary function",
            "functionalFailure": "Failure description",
            "failureMode": "Mechanism due to Cause",
            "failureEffect": "Local impact",
            "consequenceCategory": "Evident - Operational",
            "iso14224Code": "Wear",
            "severity": 7,
            "occurrence": 4,
            "detection": 5,
            "maintenanceTask": "Specific action",
            "interval": "Monthly",
            "taskType": "Condition Monitoring",
            "componentIntel": {
              "description": "Technical specs",
              "location": "Asset location",
              "visualCues": "Markers"
            }
          }
        }
        </ACTION>
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA, the Facilitator. You help teams build complete, ISO-compliant RCM studies. You wrap all specific record suggestions in <ACTION> JSON tags."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Audit results generated below.", proposals, isFacilitatorInsight: true }]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        CURRENT STUDY DATA: ${JSON.stringify((data || []).slice(-15).map(i => ({ comp: i.component, fail: i.failureMode, task: i.maintenanceTask })))}

        USER SUGGESTION/RESPONSE: "${userMsg}"

        FACILITATOR INSTRUCTIONS:
        1. Act as MIRA, a Senior RCM Facilitator.
        2. If the user suggests an addition or improvement, YOU MUST SYNTHESIZE the full technical record. 
        3. DO NOT just write "New Component". Perform engineering reasoning to determine the Function, Functional Failure, Failure Mode, Effect, S/O/D Scores, and the Task.
        4. Every addition MUST be a complete JSON object in <ACTION> tags.

        JSON SCHEMA MANDATE:
        {
          "type": "ADD",
          "reason": "Why this addition is valid",
          "item": {
            "component": "Specific Component Name",
            "function": "Specific Technical Function",
            "functionalFailure": "How it fails to meet function",
            "failureMode": "Mechanism due to Cause",
            "failureEffect": "Specific Operational/Safety Impact",
            "consequenceCategory": "Evident - Operational" | "Evident - Safety/Env" | etc,
            "iso14224Code": "Standard code",
            "severity": 1-10,
            "occurrence": 1-10,
            "detection": 1-10,
            "maintenanceTask": "Specific technical task",
            "interval": "Frequency",
            "taskType": "Strategy Category",
            "componentIntel": { "description": "Technical specs", "location": "Asset location", "visualCues": "Visual IDs" }
          }
        }
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA. You facilitate RCM workshops. You never provide partial records. You always synthesize complete engineering data in <ACTION> JSON tags when the user suggests a change."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Analysis complete.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Facilitator offline." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const s = Number(proposal.item.severity) || 5;
      const o = Number(proposal.item.occurrence) || 3;
      const d = Number(proposal.item.detection) || 4;

      // STRICT SYNTHESIS: Every field is mapped from MIRA's JSON
      const newItem: RCMItem = {
        id: `rcm-mir-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'Synthesized Component',
        function: proposal.item.function || 'General operational function.',
        functionalFailure: proposal.item.functionalFailure || 'Operational loss or degradation.',
        failureMode: proposal.item.failureMode || 'General degradation mechanism.',
        failureEffect: proposal.item.failureEffect || 'System operational impact.',
        consequenceCategory: (proposal.item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'UNC',
        criticality: proposal.item.criticality as any || (s >= 8 ? 'High' : s >= 5 ? 'Medium' : 'Low'),
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        maintenanceTask: proposal.item.maintenanceTask || 'General Inspection',
        interval: proposal.item.interval || 'Annually',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        componentIntel: {
          description: proposal.item.componentIntel?.description || 'Synchronized via MIRA logic synthesis.',
          location: proposal.item.componentIntel?.location || 'Asset assembly location.',
          visualCues: proposal.item.componentIntel?.visualCues || 'Component visual markers.'
        },
        isNew: true
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE') {
      newData = newData.map(item => {
        // Match by ID if provided, otherwise try component+failureMode match
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : (item.component === proposal.item?.component && item.failureMode === proposal.item?.failureMode);
        if (isMatch) {
          const updated = { ...item, ...proposal.item, isNew: false };
          updated.severity = Number(updated.severity) || item.severity;
          updated.occurrence = Number(updated.occurrence) || item.occurrence;
          updated.detection = Number(updated.detection) || item.detection;
          updated.rpn = updated.severity * updated.occurrence * updated.detection;
          return updated;
        }
        return item;
      });
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[700px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-slate-900 p-6 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-2 bg-indigo-500/20 rounded-xl border border-indigo-400/30">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-xl tracking-tighter uppercase leading-none">MIRA <span className="text-[10px] text-indigo-400 tracking-widest ml-1">Facilitator</span></h3>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] mt-1">Socratic Reliability Workshop</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-all"><ChevronDown size={28} /></button>
          </div>

          <div className="bg-indigo-50/50 px-6 py-3 border-b border-indigo-100 flex items-center justify-between gap-3 shrink-0">
             <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-widest">
               <ShieldAlert size={14} /> Workshop Audit
             </div>
             <button 
               onClick={handleFacilitatorAudit} 
