      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { 
            type: Type.STRING, 
            description: "A concise technical physical description (2-3 sentences)." 
          },
          location: { type: Type.STRING, description: "Where it is typically found on the asset." },
          visualCues: { type: Type.STRING, description: "What to look for to identify it." }
        },
        required: ["description", "location", "visualCues"]
      },
      failureMode: { 
        type: Type.STRING,
        description: "[Mechanism] due to [Cause]. E.g., 'Bearing seizure due to lack of lubrication'."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "Immediate impact on safety, environment, and operations."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ],
        description: "SAE JA1011 Consequence classification."
      },
      iso14224Code: {
        type: Type.STRING,
        description: "Standard failure code (e.g., Wear, Corrosion, Fatigue)."
      },
      criticality: { 
        type: Type.STRING, 
        enum: ["High", "Medium", "Low"],
