export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    You are a world-class RCM Facilitator (SAE JA1011 Specialist).
    Analyze the following operational context: ${contextText}

    TASK:
    Generate a Classical RCM Decision Sheet. 

    HIERARCHY RULES:
    1. SYSTEM FUNCTIONS: Define functions at the SYSTEM level (Primary vs Secondary).
    2. FUNCTIONAL FAILURES: Define how the system fails to perform those specific functions.
    3. COMPONENT FAILURE MODES: For each functional failure, identify the specific components and their failure mechanisms that lead to that failure.

    MANDATORY QUANTITY & FIDELITY:
    - Generate 30 to 40 unique failure modes.
    - Multiple components can contribute to the same Functional Failure.
    - Ensure a mix of mechanical, electrical, and human factors.
    - Every failure mode must be complete with Effect, Criticality (S/O/D), and a specific Maintenance Task.
  `;

  const contents: any[] = [{ parts: [{ text: prompt }] }];
  if (fileData) {
    contents[0].parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents[0].parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      temperature: 0.7
    }
  });

  const rawItems = JSON.parse(response.text || "[]");
  return rawItems.map((item: any) => ({
    ...item,
    id: `rcm-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
    isNew: true
  }));
};

export const generateInspectionSheet = async (item: RCMItem): Promise<InspectionSheet> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `
    Generate a detailed maintenance inspection protocol for:
    Component: ${item.component}
    Failure Mode: ${item.failureMode}
    Maintenance Task: ${item.maintenanceTask}

    The procedure should be practical for a field technician.
    Include step-by-step actions, techniques (Visual, Ultrasonic, etc.), and clear pass/fail criteria.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: inspectionSchema,
    }
  });

  return JSON.parse(response.text || "{}") as InspectionSheet;
};

export const generateComponentIntel = async (componentName: string): Promise<ComponentIntel> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Provide a technical physical description and identification guide for industrial component: ${componentName}.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: componentIntelSchema,
    }
  });

