export const extractOperationalContext = async (fileData: FileData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = "Extract and summarize the operational context of the industrial asset described in this document. Focus on operating environment, duty cycles, technical specifications, and historical failure data. Provide a clean, structured text output.";

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: prompt },
        { inlineData: { mimeType: fileData.mimeType, data: fileData.data } }
      ]
    }
  });

  return response.text || "";
};

