// Define the expected output schema for structured JSON
const rcmSchema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      function: { 
        type: Type.STRING,
        description: "The SYSTEM-level function. MUST start with 'Primary: ' or 'Secondary: ' (e.g., 'Primary: To pump water at 500gpm')."
      },
      functionalFailure: { 
        type: Type.STRING,
        description: "The SYSTEM-level inability to meet the function (e.g., 'Total loss of flow')."
      },
      component: { 
        type: Type.STRING, 
        description: "Specific component contributing to this failure (e.g., 'Impeller')." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { 
            type: Type.STRING, 
            description: "A concise technical physical description." 
          },
          location: { type: Type.STRING, description: "Where it is typically found." },
          visualCues: { type: Type.STRING, description: "Identification markers." }
        },
        required: ["description", "location", "visualCues"]
      },
      failureMode: { 
        type: Type.STRING,
        description: "Mechanism due to Cause (e.g., 'Bearing seizure due to lack of lubrication')."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "Immediate impact on safety and operations."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ],
        description: "Consequence classification."
      },
      iso14224Code: {
        type: Type.STRING,
        description: "Standard failure code."
      },
      criticality: { 
        type: Type.STRING, 
        enum: ["High", "Medium", "Low"],
        description: "Qualitative priority."
      },
      severity: {
        type: Type.INTEGER,
        description: "Severity (1-10)."
      },
      occurrence: {
        type: Type.INTEGER,
        description: "Occurrence (1-10)."
      },
      detection: {
        type: Type.INTEGER,
        description: "Detection (1-10)."
      },
      maintenanceTask: { 
        type: Type.STRING,
        description: "Recommended action."
      },
      interval: { 
        type: Type.STRING,
        description: "Frequency."
      },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement',
          'Training',
          'Procedural Change'
        ],
        description: "Strategy category."
      }
    },
    required: ["function", "functionalFailure", "component", "componentIntel", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

const inspectionSchema = {
  type: Type.OBJECT,
  properties: {
    responsibility: { type: Type.STRING },
    estimatedTime: { type: Type.STRING },
    safetyPrecautions: { type: Type.STRING },
    toolsRequired: { type: Type.STRING },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          step: { type: Type.INTEGER },
          description: { type: Type.STRING },
          criteria: { type: Type.STRING },
          technique: { type: Type.STRING }
        },
        required: ["step", "description", "criteria", "technique"]
      }
    }
  },
  required: ["responsibility", "estimatedTime", "safetyPrecautions", "toolsRequired", "steps"]
};

const componentIntelSchema = {
  type: Type.OBJECT,
  properties: {
    description: { type: Type.STRING },
    location: { type: Type.STRING },
