};

export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    Analyze: ${contextText}
    TASK: Generate a Classical RCM Decision Sheet. 
    RULES:
    1. FUNCTIONS: MUST start with 'Primary: ' or 'Secondary: '.
    2. FAILURES: SYSTEM level.
    3. MODES: Component level mechanisms.

    Quantity: 30-40 unique modes.
  `;

  const contents: any[] = [{ parts: [{ text: prompt }] }];
  if (fileData) {
    contents[0].parts.push({
      inlineData: { mimeType: fileData.mimeType, data: fileData.data }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents[0].parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      temperature: 0.7
    }
  });

  const rawItems = JSON.parse(response.text || "[]");
  return rawItems.map((item: any) => ({
    ...item,
    id: `rcm-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
    isNew: true
  }));
};

export const generateInspectionSheet = async (item: RCMItem): Promise<InspectionSheet> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `
    Generate inspection protocol for:
    Component: ${item.component}
    Mode: ${item.failureMode}
    Task: ${item.maintenanceTask}
  `;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: { responseMimeType: "application/json", responseSchema: inspectionSchema }
  });
  return JSON.parse(response.text || "{}") as InspectionSheet;
};

export const generateComponentIntel = async (componentName: string): Promise<ComponentIntel> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Tech info for: ${componentName}`,
    config: { responseMimeType: "application/json", responseSchema: componentIntelSchema }
  });
  return JSON.parse(response.text || "{}") as ComponentIntel;
};

export const extractOperationalContext = async (fileData: FileData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: "Extract context summarize asset." },
        { inlineData: { mimeType: fileData.mimeType, data: fileData.data } }
      ]
    }
  });
  return response.text || "";
};

