                <th className="px-6 py-4 min-w-[150px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('consequenceCategory')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">Consequence {renderSortIcon('consequenceCategory')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Filter..." value={searchFilters.consequenceCategory} onChange={(e) => handleSearchChange('consequenceCategory', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 outline-none" /></div></div></th>
                <th className="px-6 py-4 min-w-[120px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('iso14224Code')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">ISO 14224 {renderSortIcon('iso14224Code')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Filter..." value={searchFilters.iso14224Code} onChange={(e) => handleSearchChange('iso14224Code', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 outline-none" /></div></div></th>
                <th className="px-6 py-4 min-w-[180px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('failureMode')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">Failure Mode {renderSortIcon('failureMode')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Filter..." value={searchFilters.failureMode} onChange={(e) => handleSearchChange('failureMode', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 outline-none" /></div></div></th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50 border-l border-slate-200">S</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50">O</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50">D</th>
                <th className="px-4 py-4 min-w-[100px] text-left bg-slate-100/50 border-r border-slate-200"><button onClick={() => requestSort('rpn')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">RPN {renderSortIcon('rpn')}</button></th>
                <th className="px-6 py-4 min-w-[180px]">Proposed Task</th>
                <th className="px-6 py-4 w-16 text-center"><button onClick={() => requestSort('inspectionSheet')} className="flex items-center gap-1 hover:text-indigo-600 transition-colors mx-auto">Insp. {renderSortIcon('inspectionSheet')}</button></th>
                <th className="px-6 py-4 w-20 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm bg-white">
              {Object.keys(groupedHierarchy).length === 0 ? (
                <tr><td colSpan={15} className="text-center py-20 bg-slate-50/30"><div className="flex flex-col items-center gap-2 text-slate-400"><FilterX size={48} strokeWidth={1} /><p className="font-medium">No results generated or matched.</p></div></td></tr>
              ) : (
                Object.entries(groupedHierarchy).map(([func, functionalFailures]) => (
                  <React.Fragment key={func}>
                    <tr className="bg-slate-900 border-y border-slate-800">
                      <td colSpan={15} className="px-6 py-4">
                        <div className="flex items-center gap-4">
                          <div className="p-1.5 bg-indigo-600 rounded-lg text-white">
                            <Activity size={16} />
                          </div>
                          <div>
                            <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em] block mb-1">System Function</span>
                            <span className="text-sm font-black text-white uppercase tracking-tight">{func}</span>
                          </div>
                          <div className="ml-auto">
                            <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${func.toLowerCase().includes('secondary') ? 'bg-amber-500/10 text-amber-500 border border-amber-500/20' : 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20'}`}>
                              {func.toLowerCase().includes('secondary') ? 'Secondary' : 'Primary'}
                            </span>
                          </div>
                        </div>
                      </td>
                    </tr>

                    {Object.entries(functionalFailures).map(([ff, items]) => (
                      <React.Fragment key={ff}>
                        <tr className="bg-slate-100 border-b border-slate-200">
                          <td colSpan={15} className="px-10 py-3">
                            <div className="flex items-center gap-3">
                              <ShieldAlert size={14} className="text-slate-500" />
                              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Functional Failure:</span>
                              <span className="text-xs font-bold text-slate-800 uppercase italic">{ff}</span>
                            </div>
                          </td>
                        </tr>

                        {items.map((item) => {
                          const isEditing = editingId === item.id;
                          const isRegenerating = regeneratingIds.has(item.id);
                          if (isEditing && editForm) {
                            return (
                              <tr key={item.id} className="bg-indigo-50/30 ring-2 ring-indigo-500/20 z-10 relative">
                                <td className="px-6 py-4 align-top"><input type="text" value={editForm.component} onChange={(e) => handleChange('component', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /></td>
                                <td className="px-6 py-4 align-top"><select value={editForm.consequenceCategory} onChange={(e) => handleChange('consequenceCategory', e.target.value)} className="w-full px-2 py-1 border rounded text-[10px]">{CONSEQUENCE_LABELS.map(cat => <option key={cat} value={cat}>{cat}</option>)}</select></td>
                                <td className="px-6 py-4 align-top"><input type="text" value={editForm.iso14224Code} onChange={(e) => handleChange('iso14224Code', e.target.value)} className="w-full px-2 py-1 border rounded text-[10px]" /></td>
                                <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={2} value={editForm.failureMode} onChange={(e) => handleChange('failureMode', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /><textarea rows={3} value={editForm.failureEffect} onChange={(e) => handleChange('failureEffect', e.target.value)} className="w-full px-2 py-1 border rounded text-[10px] text-slate-400" /></div></td>
                                <td className="px-2 py-4 align-top bg-white/50 border-l"><input type="number" min="1" max="10" value={editForm.severity} onChange={(e) => handleChange('severity', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                                <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.occurrence} onChange={(e) => handleChange('occurrence', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                                <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.detection} onChange={(e) => handleChange('detection', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                                <td className="px-4 py-4 align-top text-center font-bold bg-white/50 border-r">{(editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1)}</td>
                                <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={3} value={editForm.maintenanceTask} onChange={(e) => handleChange('maintenanceTask', e.target.value)} className="w-full border rounded text-xs" /><input type="text" value={editForm.interval} onChange={(e) => handleChange('interval', e.target.value)} className="w-full border rounded text-[10px]" /></div></td>
                                <td className="px-6 py-4 align-top text-center text-slate-300"><File size={20} className="mx-auto" /></td>
                                <td className="px-6 py-4 align-top text-right"><div className="flex flex-col gap-2 items-end"><button onClick={handleSave} className="p-2 bg-emerald-500 text-white rounded"><Save size={16} /></button><button onClick={handleCancel} className="p-2 bg-slate-200 text-slate-600 rounded"><X size={16} /></button></div></td>
                              </tr>
                            );
                          }

                          const rpn = item.rpn || 0;
                          const rpnStyle = getRPNColorStyle(rpn);
                          const isNew = item.isNew === true;
                          return (
                            <tr key={item.id} className={`group hover:bg-slate-50 ${isRegenerating ? 'opacity-60 bg-slate-50' : ''} ${barFilter === item.id ? 'bg-indigo-50/50' : ''} ${isNew ? 'bg-emerald-50/60' : ''}`}>
                              <td className="px-6 py-4 align-top font-bold text-xs">
                                <div className="flex items-center gap-2">
                                   <span className="flex-1 text-slate-900">{item.component}</span>
                                   <button onClick={() => setSelectedIntel(item)} className="p-1 text-slate-300 hover:text-indigo-600 opacity-0 group-hover:opacity-100"><Info size={14} /></button>
                                </div>
                              </td>
                              <td className="px-6 py-4 align-top"><span className={`text-[9px] font-black px-1.5 py-0.5 rounded-full border border-slate-200 bg-white`}>{item.consequenceCategory}</span></td>
                              <td className="px-6 py-4 align-top font-mono text-[9px] font-black text-indigo-600">{item.iso14224Code}</td>
                              <td className="px-6 py-4 align-top"><div className="space-y-1"><div className="font-bold text-[11px] text-slate-900 leading-tight">{item.failureMode}</div><div className="text-slate-400 text-[9px] leading-relaxed line-clamp-2">{item.failureEffect}</div></div></td>
                              <td className="px-2 py-4 align-middle text-center border-l"><span className={getScoreColor(item.severity || 0)}>{item.severity || 0}</span></td>
                              <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.occurrence || 0)}>{item.occurrence || 0}</span></td>
                              <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.detection || 0)}>{item.detection || 0}</span></td>
                              <td className="px-4 py-4 align-middle border-r"><div className="flex flex-col gap-1"><span className={`text-xs font-bold ${rpnStyle.text}`}>{rpn}</span><div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${rpnStyle.bar}`} style={{width: `${Math.min((rpn/400)*100, 100)}%`}}></div></div></div></td>
                              <td className="px-6 py-4 align-top"><div className="font-bold text-[11px] text-slate-800 leading-tight">{item.maintenanceTask}</div><div className="text-[10px] text-indigo-600 font-black uppercase tracking-widest mt-1">{item.interval}</div></td>
                              <td className="px-6 py-4 align-middle text-center">{isRegenerating ? <RefreshCw size={20} className="animate-spin text-indigo-500 mx-auto" /> : item.inspectionSheet ? <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={22} /></button> : <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-500"><File size={22} /></button>}</td>
                              <td className="px-6 py-4 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity"><div className="flex justify-end gap-1"><button onClick={() => handleEdit(item)} className="p-1 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button><button onClick={() => handleDelete(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button></div></td>
                            </tr>
                          );
                        })}
                      </React.Fragment>
                    ))}
                  </React.Fragment>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel } from '../types';
import { generateInspectionSheet, generateComponentIntel } from '../services/geminiService';
import { IntervalOptimizerModal } from './IntervalOptimizerModal';
import { CMMSBridgeModal } from './CMMSBridgeModal';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, Printer, Copy, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, Sparkles, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, LayoutList, Target, Palette, Image as ImageIcon, Box, Layers, UserPlus, Component, HardHat
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
}

const CONSEQUENCE_LABELS: ConsequenceCategory[] = [
  'Hidden - Safety/Env', 
  'Hidden - Operational', 
  'Evident - Safety/Env', 
  'Evident - Operational',
  'Evident - Non-Operational'
];

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

const getFunctionPriority = (f: string) => {
  const lower = (f || '').toLowerCase();
  if (lower.startsWith('primary')) return 0;
  if (lower.startsWith('secondary')) return 1;
  return 2;
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, onUpdate, onUndo, canUndo }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet'; direction: 'asc' | 'desc' }>({ key: 'function', direction: 'asc' });
  const [searchFilters, setSearchFilters] = useState({
    function: '',
    functionalFailure: '',
    component: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [generatingIntel, setGeneratingIntel] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [showCMMSBridge, setShowCMMSBridge] = useState(false);

  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());
  const [copied, setCopied] = useState(false);
  const [classicalCopied, setClassicalCopied] = useState(false);

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => item !== null && item !== undefined);

    if (matrixFilter) {
      result = result.filter(item => 
        (item.severity || 0) === matrixFilter.s && 
        (item.occurrence || 0) === matrixFilter.o
      );
    }

    if (barFilter) {
      result = result.filter(item => item.id === barFilter);
    }

    if (searchFilters.function) {
      result = result.filter(item => (item.function || '').toLowerCase().includes(searchFilters.function.toLowerCase()));
    }
    if (searchFilters.functionalFailure) {
      result = result.filter(item => (item.functionalFailure || '').toLowerCase().includes(searchFilters.functionalFailure.toLowerCase()));
    }
    if (searchFilters.component) {
      result = result.filter(item => (item.component || '').toLowerCase().includes(searchFilters.component.toLowerCase()));
    }
    if (searchFilters.failureMode) {
      result = result.filter(item => (item.failureMode || '').toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    }
    if (searchFilters.consequenceCategory) {
      result = result.filter(item => (item.consequenceCategory || '').toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    }
    if (searchFilters.iso14224Code) {
      result = result.filter(item => (item.iso14224Code || '').toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));
    }

    result.sort((a, b) => {
      const aPri = getFunctionPriority(a.function || '');
      const bPri = getFunctionPriority(b.function || '');
      if (aPri !== bPri) return aPri - bPri;

      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;

      if (sortConfig.key === 'status_color') {
        const aVal = (a.isNew ? 1 : 0) * 1000 + (a.rpn || 0);
        const bVal = (b.isNew ? 1 : 0) * 1000 + (b.rpn || 0);
        return (bVal - aVal) * multiplier;
      }

      if (sortConfig.key === 'inspectionSheet') {
        const aHas = a.inspectionSheet ? 1 : 0;
        const bHas = b.inspectionSheet ? 1 : 0;
        return (aHas - bHas) * multiplier;
      }

      const aVal = a[sortConfig.key as keyof RCMItem];
      const bVal = b[sortConfig.key as keyof RCMItem];

      if (aVal === bVal) return 0;
      if (aVal === undefined || aVal === null) return 1;
      if (bVal === undefined || bVal === null) return -1;

      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return aVal.localeCompare(bVal) * multiplier;
      }
      return ((aVal as number) - (bVal as number)) * multiplier;
    });

    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const groupedHierarchy = useMemo(() => {
    const groups: Record<string, Record<string, RCMItem[]>> = {};
    processedData.forEach(item => {
      const f = item.function || "General Operations";
      const ff = item.functionalFailure || "Unknown Failure Mode";
      if (!groups[f]) groups[f] = {};
      if (!groups[f][ff]) groups[f][ff] = [];
      groups[f][ff].push(item);
    });
    return groups;
  }, [processedData]);

  const handleInternalUndo = () => {
    onUndo();
    setTimeout(() => {
       if (viewSheet) {
          const updatedItem = data.find(i => i.id === viewSheet.item.id);
          if (updatedItem) setViewSheet({ item: updatedItem });
       }
       if (selectedIntel) {
          const updatedItem = data.find(i => i.id === selectedIntel.id);
          if (updatedItem) setSelectedIntel(updatedItem);
       }
    }, 0);
  };

  const requestSort = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    } else if (key === 'rpn' || key === 'status_color' || key === 'inspectionSheet') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const handleSearchChange = (field: keyof typeof searchFilters, value: string) => {
    setSearchFilters(prev => ({ ...prev, [field]: value }));
  };

  const handleDelete = (id: string) => {
    const newData = data.filter(item => item.id !== id);
    onUpdate(newData);
    if (viewSheet?.item.id === id) setViewSheet(null);
  };

  const handleEdit = (item: RCMItem) => {
    setEditingId(item.id);
    setEditForm({ ...item });
  };

  const handleCancel = () => {
    setEditingId(null);
    setEditForm(null);
  };

  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const originalItem = data.find(d => d.id === editingId);
    if (!originalItem) return;
    const hasCriticalChanges = 
      editForm.maintenanceTask !== originalItem.maintenanceTask ||
      editForm.failureMode !== originalItem.failureMode ||
      editForm.component !== originalItem.component;
    const needsRegeneration = hasCriticalChanges && !!originalItem.inspectionSheet;
    const updatedForm = {
       ...editForm,
       rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1),
       inspectionSheet: needsRegeneration ? undefined : editForm.inspectionSheet,
       isNew: false
    };
    const newData = data.map(item => item.id === editingId ? updatedForm : item);
    onUpdate(newData);
    setEditingId(null);
    setEditForm(null);
    if (needsRegeneration) {
      setRegeneratingIds(prev => new Set(prev).add(updatedForm.id));
      try {
        const newSheet = await generateInspectionSheet(updatedForm);
        const finalData = newData.map(item => 
          item.id === updatedForm.id ? { ...item, inspectionSheet: newSheet } : item
        );
        onUpdate(finalData);
      } catch (err) { console.error("Failed to auto-regenerate sheet", err); } finally {
        setRegeneratingIds(prev => {
          const next = new Set(prev);
          next.delete(updatedForm.id);
          return next;
        });
      }
    }
  };

  const handleChange = (field: keyof RCMItem, value: any) => {
    if (!editForm) return;
    setEditForm({ ...editForm, [field]: value });
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) {
      alert("All items already have inspection sheets generated.");
      return;
    }
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 3;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const sheet = await generateInspectionSheet(item);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], inspectionSheet: sheet };
        } catch (e) { console.error(e); }
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
    setGeneratingSheets(false);
  };

  const handleGenerateMissingIntel = async () => {
    const itemsToProcess = data.filter(item => !item.componentIntel || !item.componentIntel.description);
    if (itemsToProcess.length === 0) {
      alert("All components already have physical intelligence metadata.");
      return;
    }
    setGeneratingIntel(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 4;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const intel = await generateComponentIntel(item.component);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], componentIntel: intel };
        } catch (e) { console.error(e); }
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
