      const functionType = isPrimary ? "Primary" : (isSecondary ? "Secondary" : "N/A");
      const cleanFunction = functionText.replace(/^(primary|secondary):\s*/i, "");

      const baseCols = [
        cleanForExcel(cleanFunction),
