                          const rpnStyle = getRPNColorStyle(item.rpn);
                          return (
                            <tr key={item.id} className={`group hover:bg-slate-50 transition-colors ${barFilter === item.id ? 'bg-indigo-50/50' : ''}`}><td className="px-6 py-4 align-top font-bold text-xs"><div className="flex items-center gap-2"><span className="truncate">{item.component}</span><button onClick={() => setSelectedIntel(item)} className="p-1 text-slate-300 hover:text-indigo-600 opacity-0 group-hover:opacity-100"><Info size={12} /></button></div></td><td className="px-6 py-4 align-top"><div className="font-bold text-[11px] leading-tight text-slate-900">{item.failureMode}</div><div className="text-[9px] text-slate-400 mt-1 line-clamp-1">{item.failureEffect}</div></td><td className="px-6 py-4 align-top"><span className="text-[9px] font-black uppercase tracking-tighter px-1.5 py-0.5 border rounded-full border-slate-200">{item.consequenceCategory}</span></td><td className="px-2 py-4 align-top text-center border-l bg-slate-50/30"><span className={getScoreColor(item.severity)}>{item.severity}</span></td><td className="px-2 py-4 align-top text-center bg-slate-50/30"><span className={getScoreColor(item.occurrence)}>{item.occurrence}</span></td><td className="px-2 py-4 align-top text-center bg-slate-50/30"><span className={getScoreColor(item.detection)}>{item.detection}</span></td><td className="px-4 py-4 align-top text-center border-r bg-slate-50/30"><div className="flex flex-col items-center gap-1"><span className={`text-[11px] font-black ${rpnStyle.text}`}>{item.rpn}</span><div className="w-8 h-1 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${rpnStyle.bar}`} style={{width: `${Math.min((item.rpn/300)*100, 100)}%`}}></div></div></div></td><td className="px-6 py-4 align-top font-bold text-[11px] text-slate-800 leading-tight uppercase">{item.maintenanceTask}</td><td className="px-6 py-4 align-top font-black text-[10px] text-indigo-600 uppercase tracking-widest">{item.interval}</td><td className="px-6 py-4 align-top text-center">{regeneratingIds.has(item.id) ? <RefreshCw size={18} className="animate-spin text-indigo-500 mx-auto" /> : item.inspectionSheet ? <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={20} /></button> : <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-500"><File size={20} /></button>}</td><td className="px-6 py-4 align-top text-right opacity-0 group-hover:opacity-100 transition-opacity"><div className="flex justify-end gap-1"><button onClick={() => handleEdit(item)} className="p-1 text-slate-400 hover:text-indigo-600"><Pencil size={14} /></button><button onClick={() => handleDelete(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={14} /></button></div></td></tr>
                          );
                        })}
                      </React.Fragment>
                    ))}
                  </React.Fragment>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel } from '../types';
import { generateInspectionSheet, generateComponentIntel } from '../services/geminiService';
import { IntervalOptimizerModal } from './IntervalOptimizerModal';
import { CMMSBridgeModal } from './CMMSBridgeModal';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, Printer, Copy, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, Sparkles, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, LayoutList, Target, Palette, Image as ImageIcon, Box, Layers, UserPlus, Component, HardHat
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
}

const CONSEQUENCE_LABELS: ConsequenceCategory[] = [
  'Hidden - Safety/Env', 
  'Hidden - Operational', 
  'Evident - Safety/Env', 
  'Evident - Operational',
  'Evident - Non-Operational'
];

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

const getFunctionPriority = (f: string) => {
  const lower = (f || '').toLowerCase();
  if (lower.startsWith('primary')) return 0;
  if (lower.startsWith('secondary')) return 1;
  return 2;
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, onUpdate, onUndo, canUndo }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet'; direction: 'asc' | 'desc' }>({ key: 'function', direction: 'asc' });
  const [searchFilters, setSearchFilters] = useState({
    function: '',
    functionalFailure: '',
    component: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [generatingIntel, setGeneratingIntel] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [showCMMSBridge, setShowCMMSBridge] = useState(false);

  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());
  const [copied, setCopied] = useState(false);
  const [classicalCopied, setClassicalCopied] = useState(false);

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => item !== null && item !== undefined);

    if (matrixFilter) {
      result = result.filter(item => 
        (item.severity || 0) === matrixFilter.s && 
        (item.occurrence || 0) === matrixFilter.o
      );
    }

    if (barFilter) {
      result = result.filter(item => item.id === barFilter);
    }

    if (searchFilters.function) {
      result = result.filter(item => (item.function || '').toLowerCase().includes(searchFilters.function.toLowerCase()));
    }
    if (searchFilters.functionalFailure) {
      result = result.filter(item => (item.functionalFailure || '').toLowerCase().includes(searchFilters.functionalFailure.toLowerCase()));
    }
    if (searchFilters.component) {
      result = result.filter(item => (item.component || '').toLowerCase().includes(searchFilters.component.toLowerCase()));
    }
    if (searchFilters.failureMode) {
      result = result.filter(item => (item.failureMode || '').toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    }
    if (searchFilters.consequenceCategory) {
      result = result.filter(item => (item.consequenceCategory || '').toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    }
    if (searchFilters.iso14224Code) {
      result = result.filter(item => (item.iso14224Code || '').toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));
    }

    result.sort((a, b) => {
      const aPri = getFunctionPriority(a.function || '');
      const bPri = getFunctionPriority(b.function || '');
      if (aPri !== bPri) return aPri - bPri;

      // Group sub-sort by Functional Failure to keep table orderly
      if (a.function === b.function) {
        if (a.functionalFailure !== b.functionalFailure) {
          return (a.functionalFailure || '').localeCompare(b.functionalFailure || '');
        }
      }

      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      if (sortConfig.key === 'status_color') {
        const aVal = (a.isNew ? 1 : 0) * 1000 + (a.rpn || 0);
        const bVal = (b.isNew ? 1 : 0) * 1000 + (b.rpn || 0);
        return (bVal - aVal) * multiplier;
      }
      const aVal = a[sortConfig.key as keyof RCMItem];
      const bVal = b[sortConfig.key as keyof RCMItem];
      if (aVal === bVal) return 0;
      if (aVal === undefined || aVal === null) return 1;
      if (bVal === undefined || bVal === null) return -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') return aVal.localeCompare(bVal) * multiplier;
      return ((aVal as number) - (bVal as number)) * multiplier;
    });

    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const cleanForExcel = (text: any) => {
    if (text === undefined || text === null) return "";
    return String(text).replace(/\t/g, " ").replace(/\n/g, " ").replace(/"/g, '""');
  };

  const handleCopy = async () => {
    const headers = [
      "System Function", "Function Type", "Functional Failure", "Component", "Consequence", 
      "ISO", "Failure Mode", "Failure Effect", "S", "O", "D", "RPN", 
      "Proposed Task", "Frequency", "Responsibility", "Estimated Time", 
      "Safety", "Tools", "Step No.", "Action", "Method", "Acceptance Criteria"
    ];

    const rows: string[] = [];
    processedData.forEach(item => {
      const sheet = item.inspectionSheet;
      const fText = item.function || "";
      const fType = fText.toLowerCase().includes('primary') ? "Primary" : (fText.toLowerCase().includes('secondary') ? "Secondary" : "N/A");
      const fName = fText.replace(/^(primary|secondary):\s*/i, "");

      const baseInfo = [
        cleanForExcel(fName), cleanForExcel(fType), cleanForExcel(item.functionalFailure),
        cleanForExcel(item.component), cleanForExcel(item.consequenceCategory),
        cleanForExcel(item.iso14224Code), cleanForExcel(item.failureMode), cleanForExcel(item.failureEffect),
        cleanForExcel(item.severity), cleanForExcel(item.occurrence), cleanForExcel(item.detection), cleanForExcel(item.rpn),
        cleanForExcel(item.maintenanceTask), cleanForExcel(item.interval),
        cleanForExcel(sheet?.responsibility), cleanForExcel(sheet?.estimatedTime),
        cleanForExcel(sheet?.safetyPrecautions), cleanForExcel(sheet?.toolsRequired)
      ];

      if (sheet && sheet.steps && sheet.steps.length > 0) {
        sheet.steps.forEach(step => {
          const stepInfo = [cleanForExcel(step.step), cleanForExcel(step.description), cleanForExcel(step.technique), cleanForExcel(step.criteria)];
          rows.push([...baseInfo, ...stepInfo].join("\t"));
        });
      } else {
        rows.push([...baseInfo, "", "", "", ""].join("\t"));
      }
    });

    const output = [headers.join("\t"), ...rows].join("\n");
    try {
      await navigator.clipboard.writeText(output);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) { console.error(err); }
  };

  const handleClassicalCopy = async () => {
    const headers = [
      "Function Identification", "Functional Failure", "Asset Component", "Failure Mechanism (Mode)", 
      "Consequence Assessment", "S", "O", "D", "RPN Score", "Strategy Category", "Recommended Task", "Frequency"
    ];

    const rows = processedData.map(item => [
      cleanForExcel(item.function), cleanForExcel(item.functionalFailure), cleanForExcel(item.component),
      cleanForExcel(item.failureMode), cleanForExcel(item.consequenceCategory),
      cleanForExcel(item.severity), cleanForExcel(item.occurrence), cleanForExcel(item.detection), cleanForExcel(item.rpn),
      cleanForExcel(item.taskType), cleanForExcel(item.maintenanceTask), cleanForExcel(item.interval)
    ].join("\t"));

    const output = [headers.join("\t"), ...rows].join("\n");
    try {
      await navigator.clipboard.writeText(output);
      setClassicalCopied(true);
      setTimeout(() => setClassicalCopied(false), 2000);
    } catch (err) { console.error(err); }
  };

  const handleInternalUndo = () => {
    onUndo();
    setTimeout(() => {
       if (viewSheet) {
          const updatedItem = data.find(i => i.id === viewSheet.item.id);
          if (updatedItem) setViewSheet({ item: updatedItem });
       }
    }, 0);
  };

  const requestSort = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    else if (key === 'rpn' || key === 'status_color' || key === 'inspectionSheet') direction = 'desc';
    setSortConfig({ key, direction });
  };

  const handleDelete = (id: string) => {
    const newData = data.filter(item => item.id !== id);
    onUpdate(newData);
    if (viewSheet?.item.id === id) setViewSheet(null);
  };

  const handleEdit = (item: RCMItem) => {
    setEditingId(item.id);
    setEditForm({ ...item });
  };

  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const newData = data.map(item => item.id === editingId ? { ...editForm, rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1), isNew: false } : item);
    onUpdate(newData);
    setEditingId(null);
    setEditForm(null);
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) return alert("All items already have inspection sheets generated.");
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 3;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const sheet = await generateInspectionSheet(item);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], inspectionSheet: sheet };
        } catch (e) { console.error(e); }
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
    setGeneratingSheets(false);
  };

  const handleGenerateSingleSheet = async (item: RCMItem) => {
    setRegeneratingIds(prev => new Set(prev).add(item.id));
    try {
      const sheet = await generateInspectionSheet(item);
      const newData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(newData);
      const updatedItem = newData.find(d => d.id === item.id);
      if (updatedItem) setViewSheet({ item: updatedItem });
    } catch (e) { alert("Failed to generate."); } finally { 
      setRegeneratingIds(prev => { const next = new Set(prev); next.delete(item.id); return next; });
    }
  };

  const renderInspectionSheet = () => {
    if (!viewSheet) return null;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet) return null;
    const isRegenerating = regeneratingIds.has(item.id);

    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-7xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 border border-slate-100 max-h-[95vh]">
          <div className="bg-slate-900 px-10 py-8 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-6">
              <div className="p-4 bg-emerald-500/20 rounded-[1.5rem] border border-emerald-500/30 shadow-inner">
                <FileCheck size={32} className="text-emerald-200" />
              </div>
              <div>
                <h3 className="font-black text-2xl tracking-tighter uppercase leading-none">Strategy Execution Plan</h3>
                <div className="flex items-center gap-3 mt-2.5">
                   <span className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">{item.component}</span>
                   <div className="w-1 h-1 rounded-full bg-slate-700"></div>
                   <span className="text-[10px] text-emerald-400 font-black uppercase tracking-[0.2em]">Validated Asset Route</span>
                </div>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <button onClick={() => setViewSheet(null)} className="p-3 bg-white/5 text-slate-400 hover:bg-white/10 hover:text-white rounded-full transition-all">
                <X size={28} />
              </button>
            </div>
          </div>
          <div className="p-10 overflow-y-auto custom-scrollbar flex-1 bg-slate-50/50">
            {/* Summary Window */}
            <div className="mb-10 p-8 bg-white rounded-[2.2rem] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
               <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/50 rounded-bl-[100%] -mr-10 -mt-10 pointer-events-none"></div>
               <div className="flex flex-col lg:flex-row gap-10">
                 <div className="flex-1 space-y-6">
                    <div className="flex items-center gap-3"><Zap size={20} className="text-indigo-600" /><h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">Maintenance Strategic Profile</h4></div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                       <div><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Asset Component</p><p className="text-lg font-black text-slate-900 leading-none">{item.component}</p></div>
                       <div><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Proposed Strategy</p><p className="text-lg font-black text-indigo-600 leading-none">{item.maintenanceTask}</p></div>
                    </div>
                    <div><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Failure Mode Description</p><p className="text-sm font-bold text-slate-600 italic leading-relaxed">"{item.failureMode}"</p></div>
                 </div>
                 <div className="lg:w-px bg-slate-100"></div>
                 <div className="lg:w-80 space-y-6">
                    <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100"><div className="flex justify-between items-center"><div><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Interval</p><p className="text-xl font-black text-slate-900">{item.interval}</p></div><Clock className="text-indigo-600 opacity-20" size={32} /></div></div>
                    <div className="grid grid-cols-2 gap-4"><div className="text-center"><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">RPN</p><p className={`text-lg font-black ${getRPNColorStyle(item.rpn).text}`}>{item.rpn}</p></div><div className="text-center"><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Priority</p><p className={`text-lg font-black ${item.criticality === 'High' ? 'text-red-600' : 'text-emerald-600'}`}>{item.criticality}</p></div></div>
                 </div>
               </div>
            </div>
            {/* Metadata Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-10">
              <div className="bg-white p-6 rounded-[1.8rem] border border-slate-100 shadow-sm"><div className="flex items-center gap-3 mb-2 opacity-60"><User size={14} className="text-slate-900" /><span className="text-[9px] font-black uppercase tracking-widest">Responsibility</span></div><p className="text-sm font-black text-slate-900 uppercase tracking-tight">{sheet.responsibility}</p></div>
              <div className="bg-white p-6 rounded-[1.8rem] border border-slate-100 shadow-sm"><div className="flex items-center gap-3 mb-2 opacity-60"><Clock size={14} className="text-slate-900" /><span className="text-[9px] font-black uppercase tracking-widest">Estimated Time</span></div><p className="text-sm font-black text-slate-900 uppercase tracking-tight">{sheet.estimatedTime}</p></div>
              <div className="bg-white p-6 rounded-[1.8rem] border border-red-100 shadow-sm bg-red-50/10"><div className="flex items-center gap-3 mb-2"><HardHat size={14} className="text-red-600" /><span className="text-[9px] font-black uppercase tracking-widest text-red-600">Critical Safety</span></div><p className="text-[11px] font-bold text-slate-700 leading-tight">{sheet.safetyPrecautions}</p></div>
              <div className="bg-white p-6 rounded-[1.8rem] border border-slate-100 shadow-sm"><div className="flex items-center gap-3 mb-2 opacity-60"><Wrench size={14} className="text-indigo-600" /><span className="text-[9px] font-black uppercase tracking-widest">Required Tools</span></div><p className="text-[11px] font-bold text-slate-700 leading-tight">{sheet.toolsRequired}</p></div>
            </div>
            {/* Steps */}
            <div className="bg-white rounded-[2.2rem] border border-slate-200 overflow-hidden shadow-2xl">
              <table className="w-full text-left table-fixed">
                <thead className="bg-slate-900 border-b border-slate-800"><tr className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400"><th className="px-8 py-5 w-16 text-center">Step</th><th className="px-8 py-5 flex-1">Technical Action Sequence</th><th className="px-8 py-5 w-48 text-center">Method</th><th className="px-8 py-5 w-72">Acceptance Criteria</th><th className="px-8 py-5 w-24 text-right"></th></tr></thead>
                <tbody className="divide-y divide-slate-100">{sheet.steps?.map((step, idx) => (
                    <tr key={idx} className="group hover:bg-slate-50 transition-all"><td className="px-8 py-6 text-xs font-black text-indigo-600 text-center"><div className="w-8 h-8 rounded-lg bg-indigo-50 flex items-center justify-center mx-auto">{step.step}</div></td><td className="px-8 py-6"><p className="text-sm font-bold text-slate-800 leading-relaxed uppercase tracking-tight">{step.description}</p></td><td className="px-8 py-6 text-center"><div className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-indigo-50 border border-indigo-100 rounded-lg"><span className="text-[9px] font-black text-indigo-700 uppercase tracking-tighter truncate max-w-[100px]">{step.technique}</span></div></td><td className="px-8 py-6"><div className="flex items-start gap-3 p-3 bg-emerald-50/30 rounded-xl border border-emerald-100/50"><CheckCircle size={12} className="mt-0.5 text-emerald-600 shrink-0" /><p className="text-[11px] font-bold text-emerald-800 leading-tight">{step.criteria}</p></div></td><td className="px-8 py-6 text-right"></td></tr>
                  ))}</tbody>
              </table>
            </div>
          </div>
          <div className="px-10 py-8 bg-white border-t border-slate-100 flex justify-end shrink-0 shadow-[0_-10px_30px_rgba(0,0,0,0.02)]">
             <button onClick={() => setViewSheet(null)} className="px-14 py-4 bg-slate-900 text-white rounded-[1.2rem] text-[10px] font-black uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all active:scale-95 shadow-2xl">Confirm Protocol</button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-fade-in relative w-full">
      {renderInspectionSheet()}
      {optimizingItem && <IntervalOptimizerModal item={optimizingItem} isOpen={!!optimizingItem} onClose={() => setOptimizingItem(null)} onApply={(iv) => onUpdate(data.map(d => d.id === optimizingItem.id ? { ...d, interval: iv } : d))} />}
      <CMMSBridgeModal data={data} isOpen={showCMMSBridge} onClose={() => setShowCMMSBridge(false)} />

      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4">
        {[{ label: 'Modes', value: data.length, icon: ListChecks, color: 'text-blue-600' }, { label: 'High RPN', value: data.filter(i => i.rpn > 100).length, icon: AlertOctagon, color: 'text-red-600' }, { label: 'Proactive', value: data.filter(i => i.taskType !== 'Run-to-Failure').length, icon: ShieldCheck, color: 'text-emerald-600' }].map((stat, i) => (
           <div key={i} className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
            <div className="flex flex-col gap-3">
              <div className={`w-10 h-10 rounded-xl bg-slate-50 ${stat.color} flex items-center justify-center shrink-0`}><stat.icon size={20} /></div>
              <div><p className="text-[10px] text-slate-500 font-bold uppercase tracking-tight mb-1.5">{stat.label}</p><h3 className="text-xl font-bold text-slate-800">{stat.value}</h3></div>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden ring-1 ring-slate-900/5">
        <div className="p-6 border-b border-slate-200 flex flex-col xl:flex-row justify-between items-center gap-4 bg-slate-50/50">
          <div className="flex items-center gap-3"><div className="p-2 bg-indigo-600 rounded-lg text-white shadow-sm"><LayoutList size={20} /></div><div><h3 className="text-lg font-bold text-slate-800 uppercase tracking-tight">Classical RCM Decision Sheet</h3><p className="text-xs text-slate-500">Industry Standard System Hierarchy Mapping</p></div></div>
          <div className="flex flex-wrap justify-center items-center gap-3">
            <button onClick={() => setShowCMMSBridge(true)} className="px-4 py-2 text-sm font-black uppercase bg-slate-900 text-white rounded-lg flex items-center gap-2"><Layers size={16} /> CMMS Sync</button>
            <button onClick={handleGenerateAllSheets} disabled={generatingSheets} className="px-4 py-2 text-sm font-medium bg-white text-indigo-600 border border-indigo-200 rounded-lg flex items-center gap-2">{generatingSheets ? <Loader2 size={16} className="animate-spin" /> : <ClipboardList size={16} />} Protocols</button>
            <button onClick={handleCopy} className="px-3 py-2 text-sm font-medium bg-white text-slate-700 border border-slate-200 rounded-lg flex items-center gap-2">{copied ? <CheckCircle size={16} className="text-green-600" /> : <Copy size={16} />} Excel Flat Copy</button>
            <button onClick={handleClassicalCopy} className="px-3 py-2 text-sm font-medium bg-white text-slate-700 border border-slate-200 rounded-lg flex items-center gap-2">{classicalCopied ? <CheckCircle size={16} className="text-indigo-600" /> : <LayoutList size={16} />} Classical Copy</button>
          </div>
        </div>

        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse table-fixed min-w-[1600px]">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-[10px] font-black uppercase tracking-widest text-slate-500">
                <th className="px-6 py-4 w-64 border-r border-slate-100">1. System Function</th>
                <th className="px-6 py-4 w-64 border-r border-slate-100">2. Functional Failure</th>
                <th className="px-6 py-4 w-48 border-r border-slate-100">3. Component</th>
                <th className="px-6 py-4 w-72">4. Failure Mechanism (Mode)</th>
                <th className="px-6 py-4 w-48">Consequence</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/30">S</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/30">O</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/30">D</th>
                <th className="px-4 py-4 w-20 text-center bg-slate-100/30">RPN</th>
                <th className="px-6 py-4 w-72">Maintenance Task</th>
                <th className="px-6 py-4 w-32">Frequency</th>
                <th className="px-6 py-4 w-24 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="text-xs bg-white divide-y divide-slate-100">
              {processedData.length === 0 ? (
                <tr><td colSpan={12} className="py-20 text-center text-slate-400">No analytical data available. Generate insights above.</td></tr>
              ) : (
                processedData.map((item, idx) => {
                  // Logic to check if we should display Function or FF (first in group)
                  const showFunction = idx === 0 || processedData[idx-1].function !== item.function;
                  const showFF = idx === 0 || processedData[idx-1].function !== item.function || processedData[idx-1].functionalFailure !== item.functionalFailure;

                  const isEditing = editingId === item.id && editForm;
                  const rpnStyle = getRPNColorStyle(item.rpn);

                  return (
                    <tr key={item.id} className="hover:bg-slate-50/50 transition-colors align-top group">
                      <td className={`px-6 py-5 border-r border-slate-100 font-black text-slate-900 leading-tight uppercase ${!showFunction ? 'opacity-0' : 'bg-slate-50/20'}`}>
                        {item.function}
                      </td>
                      <td className={`px-6 py-5 border-r border-slate-100 font-bold text-slate-600 italic tracking-tight leading-tight ${!showFF ? 'opacity-0' : 'bg-slate-50/20'}`}>
                        {item.functionalFailure}
                      </td>
                      <td className="px-6 py-5 border-r border-slate-100 font-black text-indigo-700 uppercase tracking-tighter flex items-center gap-2">
                        <span className="truncate">{item.component}</span>
                      </td>
                      <td className="px-6 py-5">
                        {isEditing ? (
                          <textarea rows={2} value={editForm.failureMode} onChange={(e) => setEditForm({ ...editForm, failureMode: e.target.value })} className="w-full p-2 border rounded" />
                        ) : (
                          <div className="font-black text-slate-900 uppercase leading-snug tracking-tighter">{item.failureMode}</div>
                        )}
                        <div className="text-[10px] text-slate-400 mt-2 line-clamp-2 italic">{item.failureEffect}</div>
                      </td>
                      <td className="px-6 py-5">
                         <span className="text-[9px] font-black uppercase bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded-full border border-slate-200">{item.consequenceCategory}</span>
                      </td>
                      <td className="px-2 py-5 text-center font-bold bg-slate-50/20"><span className={getScoreColor(item.severity)}>{item.severity}</span></td>
                      <td className="px-2 py-5 text-center font-bold bg-slate-50/20"><span className={getScoreColor(item.occurrence)}>{item.occurrence}</span></td>
                      <td className="px-2 py-5 text-center font-bold bg-slate-50/20"><span className={getScoreColor(item.detection)}>{item.detection}</span></td>
                      <td className="px-4 py-5 text-center bg-slate-50/20 font-black">
                        <div className={`text-[11px] ${rpnStyle.text}`}>{item.rpn}</div>
                      </td>
                      <td className="px-6 py-5">
                         {isEditing ? (
                           <textarea rows={2} value={editForm.maintenanceTask} onChange={(e) => setEditForm({ ...editForm, maintenanceTask: e.target.value })} className="w-full p-2 border rounded" />
                         ) : (
                           <div className="font-bold text-slate-800 leading-tight uppercase tracking-tight">{item.maintenanceTask}</div>
                         )}
                         <div className="text-[9px] text-indigo-500 font-black mt-1.5 tracking-widest">{item.taskType}</div>
                      </td>
                      <td className="px-6 py-5">
                         {isEditing ? (
                           <input value={editForm.interval} onChange={(e) => setEditForm({ ...editForm, interval: e.target.value })} className="w-full p-1 border rounded" />
                         ) : (
                           <div className="font-black text-indigo-600 uppercase">{item.interval}</div>
                         )}
                      </td>
                      <td className="px-6 py-5 text-right">
                        <div className="flex justify-end gap-2 items-center">
                          {isEditing ? (
                            <button onClick={handleSave} className="p-1.5 bg-emerald-600 text-white rounded"><Save size={14} /></button>
                          ) : (
                            <>
                              {item.inspectionSheet ? (
                                <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={20} /></button>
                              ) : (
                                <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-600"><File size={20} /></button>
                              )}
                              <button onClick={() => handleEdit(item)} className="p-1 text-slate-300 hover:text-indigo-600 opacity-0 group-hover:opacity-100"><Pencil size={14} /></button>
                              <button onClick={() => handleDelete(item.id)} className="p-1 text-slate-300 hover:text-red-600 opacity-0 group-hover:opacity-100"><Trash2 size={14} /></button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};
